import { addFilter } from '@/assets/js/functions/HooksSystem.js';
import { useAppStore } from '@/store/app/app.js';

// Keep category registration separate so other pages (like Settings)
// can reuse the same registration logic without importing all cards.
const isAnalyticsEnabled = () => {
  const appStore = useAppStore();
  return Boolean(appStore.state?.uixpress_settings?.enable_uixpress_analytics);
};

addFilter('uixpress/dashboard/categories/register', (categories) => {
  const baseCategories = [
    ...categories,
    { value: 'site', label: __('Overview', 'uixpress') },
  ];

  if (isAnalyticsEnabled()) {
    baseCategories.push({ value: 'analytics', label: __('Analytics', 'uixpress') });
  }

  return baseCategories;
});
